B.eC=new A.lA(2,"subtitle")
B.i2=new A.lA(3,"trailing")
B.aJX=s([B.eB,B.d1,B.eC,B.i2],A.a6("p<lA>"))
B.TR=new A.t8(0,"auto")
B.TS=new A.t8(1,"full")
