B.fy=new A.wp(0,"leistung")
B.b5r=new A.f4(B.fy,"stets zu unserer vollsten Zufriedenheit",'Sehr gut (Note 1). \u201evollsten" ist die h\xf6chste Steigerung.',1)
B.b5p=new A.f4(B.fy,"stets zu unserer vollen Zufriedenheit",'Gut (Note 2). \u201estets" + \u201evollen", aber nicht \u201evollsten".',2)
B.b5u=new A.f4(B.fy,"zu unserer vollen Zufriedenheit",'Befriedigend (Note 3). Ohne \u201estets" \u2013 nur \u201evoll".',3)
B.b5A=new A.f4(B.fy,"stets zu unserer Zufriedenheit",'Ausreichend (Note 4). \u201estets", aber ohne \u201evoll".',4)
B.b5q=new A.f4(B.fy,"zu unserer Zufriedenheit",'Mangelhaft (Note 5). Weder \u201estets" noch \u201evoll".',5)
B.b5t=new A.f4(B.fy,"hat sich bem\xfcht, den Anforderungen gerecht zu werden",'Ungen\xfcgend (Note 6). \u201ebem\xfcht" = die Anforderungen nicht erf\xfcllt.',6)
B.jV=new A.wp(1,"verhalten")
B.b5x=new A.f4(B.jV,"Verhalten gegen\xfcber Vorgesetzten und Kollegen war stets vorbildlich",'Sehr gut. Reihenfolge Vorgesetzte \u2192 Kollegen und \u201estets vorbildlich".',1)
B.b5z=new A.f4(B.jV,"Verhalten war stets einwandfrei / vorbildlich",'Gut. \u201estets einwandfrei" liegt unter \u201estets vorbildlich".',2)
B.b5w=new A.f4(B.jV,"Verhalten gab zu keiner Klage Anlass","Nur ausreichend \u2013 eine schwache Formulierung.",4)
B.b5B=new A.f4(B.jV,"Verhalten gegen\xfcber Kollegen und Vorgesetzten (Kollegen zuerst)","Werden die Kollegen vor den Vorgesetzten genannt, deutet das auf ein gest\xf6rtes Verh\xe4ltnis zu den Vorgesetzten hin.",null)
B.ur=new A.wp(2,"schlussformel")
B.b5v=new A.f4(B.ur,"Wir bedauern sein Ausscheiden, danken f\xfcr die stets gute Zusammenarbeit und w\xfcnschen f\xfcr die Zukunft alles Gute","Positive, vollst\xe4ndige Schlussformel \u2013 ein gutes Zeichen.",null)
B.b5y=new A.f4(B.ur,"Fehlende Schlussformel (kein Dank, kein Bedauern, keine guten W\xfcnsche)","Das Fehlen der Schlussformel gilt als Distanzierung und wertet ein sonst gutes Zeugnis ab.",null)
B.o_=new A.wp(3,"code")
B.b5n=new A.f4(B.o_,"trug durch seine Geselligkeit zur Verbesserung des Betriebsklimas bei","Kann auf \xfcberm\xe4\xdfigen Alkoholkonsum anspielen.",null)
B.b5o=new A.f4(B.o_,"war stets bem\xfcht",'\u201ebem\xfcht" ohne Erfolg = die Leistung war nicht ausreichend.',null)
B.b5s=new A.f4(B.o_,"zeigte f\xfcr die Belange der Belegschaft (gro\xdfes) Verst\xe4ndnis","Kann andeuten, dass die Person mehr mit Betriebsrats-/Kollegen-Themen als mit der Arbeit besch\xe4ftigt war.",null)
